```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <algorithm>

// Function to convert a string to lowercase
std::string toLowerCase(const std::string& str) {
    std::string lowerStr = str;
    std::transform(lowerStr.begin(), lowerStr.end(), lowerStr.begin(), ::tolower);
    return lowerStr;
}

// Function to count occurrences of a specific word in a line
int countWordOccurrences(const std::string& line, const std::string& word) {
    std::istringstream iss(line);
    std::string token;
    int count = 0;

    // Read each word from the line
    while (iss >> token) {
        if (token == word) {
            count++;
        }
    }

    return count;
}

int main() {
    std::string filename, word;
    int count = 0;

    // Get the filename and word to search for from the user
    std::cout << "Enter filename: ";
    std::cin >> filename;
    std::cout << "Enter the word to search for: ";
    std::cin >> word;

    // Open the file
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file: " << filename << std::endl;
        return 1;
    }

    std::string line;
    // Read the file line by line
    while (std::getline(file, line)) {
        std::string lowerLine = toLowerCase(line);
        std::string lowerWord = toLowerCase(word);
        count += countWordOccurrences(lowerLine, lowerWord);
    }

    // Close the file
    file.close();

    // Output the count
    std::cout << "The word '" << word << "' occurs " << count << " times in the file '" << filename << "'." << std::endl;

    return 0;
}
```

### Explanation:

1. **Include Headers**: The necessary headers `<iostream>`, `<fstream>`, `<string>`, `<sstream>`, and `<algorithm>` are included.
2. **toLowerCase Function**: This function converts a string to lowercase to handle case-insensitive comparisons.
3. **countWordOccurrences Function**: This function counts occurrences of a word in a given line.
4. **main Function**:
   - Prompts the user to input the filename and the word to search for.
   - Opens the file and checks if it was successfully opened.
   - Reads the file line by line, converts lines and the word to lowercase, and counts the occurrences of the word.
   - Outputs the total count of occurrences.

### To Compile and Run:

1. Save the program to a file, e.g., `word_count.cpp`.
2. Open a terminal or command prompt and navigate to the directory containing `word_count.cpp`.
3. Compile the program using a C++ compiler, e.g., `g++ word_count.cpp -o word_count`.
4. Run the compiled program, e.g., `./word_count`.

Follow the prompts to enter the filename and the word to search for, and the program will print the count of occurrences.
